class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        auto calc_price = [&](long long n) {
            long long res = 0;
            for (long long i = 1; i <= n; ++i) {
                res += __builtin_popcountll(i * x);
            }
            return res;
        };

        long long left = 0, right = k * 60 + 1;
        while (left < right) {
            long long mid = left + (right - left + 1) / 2;
            if (calc_price(mid) <= k) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }
};
```
